1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (wasAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (wasAlive && liveNeighbors === 2);
16	
17	const tallyLiveNeighbors = (cells: Cell[]): Map<string, { cell: Cell; count: number }> => {
18	  const tally = new Map<string, { cell: Cell; count: number }>();
19	  for (const cell of cells) {
20	    for (const neighbor of neighborsOf(cell)) {
21	      const key = keyOf(neighbor);
22	      const existing = tally.get(key);
23	      tally.set(key, { cell: neighbor, count: (existing?.count ?? 0) + 1 });
24	    }
25	  }
26	  return tally;
27	};
28	
29	export function nextGeneration(cells: Cell[]): Cell[] {
30	  const aliveKeys = new Set(cells.map(keyOf));
31	  const neighborCounts = tallyLiveNeighbors(cells);
32	
33	  return [...neighborCounts]
34	    .filter(([key, { count }]) => survives(aliveKeys.has(key), count))
35	    .map(([, { cell }]) => cell);
36	}
