4	describe("Game of Life - nextGeneration", () => {
5	  it("single cell dies — [(0,0)] → []", () => {
6	    expect(nextGeneration([[0, 0]])).toEqual([]);
7	  });
8	  it("Rule 1 Underpopulation: two adjacent cells both die — [(0,1), (1,1)] → []", () => {
9	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
10	  });
11	  it("Rule 4 Reproduction: dead cell with exactly 3 live neighbors becomes alive — [(0,2), (1,2), (0,1)] → [(0,2), (1,2), (0,1), (1,1)]", () => {
12	    const input: [number, number][] = [[0, 2], [1, 2], [0, 1]];
13	    const expected: [number, number][] = [[0, 2], [1, 2], [0, 1], [1, 1]];
14	    expect(nextGeneration(input).sort()).toEqual(expected.sort());
15	  });
16	  it("Rule 2 Survival: middle of a horizontal triple survives — [(0,0),(1,0),(2,0)] includes (1,0) in next gen", () => {
17	    const gen0: [number, number][] = [[0, 0], [1, 0], [2, 0]];
18	    const result = nextGeneration(gen0);
19	    expect(result).toContainEqual([1, 0]);
20	  });
21	  it("Rule 3 Overpopulation: center cell with 4+ live neighbors dies — full 3x3 grid, (1,1) not in result", () => {
22	    const gen0: [number, number][] = [
23	      [0, 0], [1, 0], [2, 0],
24	      [0, 1], [1, 1], [2, 1],
25	      [0, 2], [1, 2], [2, 2],
26	    ];
27	    const result = nextGeneration(gen0);
28	    expect(result).not.toContainEqual([1, 1]);
29	  });
30	  it("Block still life: 2x2 block remains unchanged — [(0,0),(1,0),(0,1),(1,1)] stays the same", () => {
31	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
32	    const result = nextGeneration(block);
33	    expect(result.sort()).toEqual(block.sort());
34	  });
35	  it("Blinker oscillator: vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
36	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
37	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
38	    const result = nextGeneration(vertical);
39	    expect(result.sort()).toEqual(expected.sort());
40	  });
