const tallyLiveNeighbors = (cells: Cell[]): Map<string, { cell: Cell; count: number }> => {
  const tally = new Map<string, { cell: Cell; count: number }>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = keyOf(neighbor);
      const existing = tally.get(key);
      tally.set(key, { cell: neighbor, count: (existing?.count ?? 0) + 1 });
    }
  }
  return tally;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(keyOf));
  const neighborCounts = tallyLiveNeighbors(cells);

  return [...neighborCounts]
    .filter(([key, { count }]) => survives(aliveKeys.has(key), count))
    .map(([, { cell }]) => cell);
}

