const candidateNeighbors = (cells: Cell[]): Cell[] =>
  cells.flatMap(neighborsOf);

export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(keyOf));
  const neighborCounts = new Map<string, number>();
  const candidates = new Map<string, Cell>();

  for (const cell of candidateNeighbors(cells)) {
    const key = keyOf(cell);
    neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
    candidates.set(key, cell);
  }

  return [...candidates]
    .filter(([key, _]) => survives(aliveKeys.has(key), neighborCounts.get(key) ?? 0))
    .map(([, cell]) => cell);
}

